/*
 * Memory Hierarchy Simulation in C
 * Demonstrates cache hit/miss behavior and AMAT calculation
 * For university 2022 Scheme - Computer Organization
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>

/* Memory hierarchy configuration */
typedef struct {
 int cache_size_kb;
 int memory_size_mb;
 int block_size; /* Cache line size */
 int access_time_ns; /* Cache access time */
 int memory_time_ns; /* Main memory access time */
 double hit_rate;
} MemoryConfig;

/* Cache statistics */
typedef struct {
 unsigned long hits;
 unsigned long misses;
 unsigned long accesses;
} CacheStats;

/* Simple direct-mapped cache simulation */
typedef struct {
 int *cache_tags; /* Tag for each cache line */
 int num_lines; /* Number of cache lines */
 int block_size; /* Bytes per block */
 CacheStats stats;
} Cache;

/* Initialize cache */
Cache* create_cache(int cache_size_kb, int block_size) {
 Cache *cache = (Cache*)malloc(sizeof(Cache));
 cache->num_lines = (cache_size_kb * 1024) / block_size;
 cache->block_size = block_size;
 cache->cache_tags = (int*)malloc(cache->num_lines * sizeof(int));

 /* Initialize all tags to -1 (invalid) */
 for (int i = 0; i < cache->num_lines; i++) {
 cache->cache_tags[i] = -1;
 }

 cache->stats.hits = 0;
 cache->stats.misses = 0;
 cache->stats.accesses = 0;

 return cache;
}

/* Simulate memory access - returns 1 for hit, 0 for miss */
int access_memory(Cache *cache, int address) {
 cache->stats.accesses++;

 /* Calculate which cache line this address maps to */
 int block_number = address / cache->block_size;
 int line_index = block_number % cache->num_lines;
 int tag = block_number / cache->num_lines;

 /* Check for hit */
 if (cache->cache_tags[line_index] == tag) {
 cache->stats.hits++;
 return 1; /* Hit */
 } else {
 cache->stats.misses++;
 cache->cache_tags[line_index] = tag; /* Load block into cache */
 return 0; /* Miss */
 }
}

/* Calculate hit rate */
double calculate_hit_rate(CacheStats *stats) {
 if (stats->accesses == 0) return 0.0;
 return (double)stats->hits / stats->accesses * 100.0;
}

/* Calculate AMAT */
double calculate_amat(int cache_time_ns, int memory_time_ns, double hit_rate_percent) {
 double h = hit_rate_percent / 100.0;
 double miss_rate = 1.0 - h;

 /* AMAT = h * Tcache + (1-h) * (Tcache + Tmemory) */
 double amat = h * cache_time_ns + miss_rate * (cache_time_ns + memory_time_ns);
 return amat;
}

/* Demonstrate temporal locality - repeated access to same location */
void demonstrate_temporal_locality(Cache *cache) {
 printf("\n--- Temporal Locality Demo ---");
 printf("\nAccessing same location 1000 times in a loop...\n");

 int address = 4096; /* Fixed address */
 for (int i = 0; i < 1000; i++) {
 access_memory(cache, address);
 }

 double hit_rate = calculate_hit_rate(&cache->stats);
 printf("Hits: %lu\n", cache->stats.hits);
 printf("Misses: %lu\n", cache->stats.misses);
 printf("Hit Rate: %.2f%%\n", hit_rate);
 printf("Explanation: Same location accessed repeatedly (temporal locality)\n");
}

/* Demonstrate spatial locality - sequential access */
void demonstrate_spatial_locality(Cache *cache) {
 printf("\n--- Spatial Locality Demo ---");
 printf("\nAccessing sequential addresses (array traversal)...\n");

 /* Reset stats */
 cache->stats.hits = 0;
 cache->stats.misses = 0;
 cache->stats.accesses = 0;

 /* Sequential access - stride equals block size for best spatial locality */
 for (int i = 0; i < 1000; i++) {
 access_memory(cache, i * cache->block_size);
 }

 double hit_rate = calculate_hit_rate(&cache->stats);
 printf("Hits: %lu\n", cache->stats.hits);
 printf("Misses: %lu\n", cache->stats.misses);
 printf("Hit Rate: %.2f%%\n", hit_rate);
 printf("Explanation: Consecutive addresses accessed (spatial locality)\n");
}

/* Compare with random access (poor locality) */
void demonstrate_random_access(Cache *cache) {
 printf("\n--- Random Access Demo ---");
 printf("\nAccessing random addresses...\n");

 /* Reset stats */
 cache->stats.hits = 0;
 cache->stats.misses = 0;
 cache->stats.accesses = 0;

 srand(42); /* Fixed seed for reproducibility */
 for (int i = 0; i < 1000; i++) {
 int random_addr = rand() % 100000;
 access_memory(cache, random_addr);
 }

 double hit_rate = calculate_hit_rate(&cache->stats);
 printf("Hits: %lu\n", cache->stats.hits);
 printf("Misses: %lu\n", cache->stats.misses);
 printf("Hit Rate: %.2f%%\n", hit_rate);
 printf("Explanation: No predictable pattern (poor locality)\n");
}

int main() {
 printf("=================================================\n");
 printf(" MEMORY HIERARCHY SIMULATION - C IMPLEMENTATION\n");
 printf("=================================================\n");

 /* Create a 4KB direct-mapped cache with 64-byte blocks */
 Cache *cache = create_cache(4, 64); /* 4 KB cache, 64-byte blocks */

 printf("Cache Configuration:\n");
 printf(" Cache Size: %d KB\n", 4);
 printf(" Block Size: %d bytes\n", 64);
 printf(" Num Lines: %d\n", cache->num_lines);

 /* Demonstrate different access patterns */
 demonstrate_temporal_locality(cache);

 /* Recreate cache for next demo */
 free(cache->cache_tags);
 free(cache);
 cache = create_cache(4, 64);

 demonstrate_spatial_locality(cache);

 /* Recreate cache for next demo */
 free(cache->cache_tags);
 free(cache);
 cache = create_cache(4, 64);

 demonstrate_random_access(cache);

 /* Calculate AMAT with different hit rates */
 printf("\n=================================================\n");
 printf(" AMAT CALCULATION EXAMPLES\n");
 printf("=================================================\n");

 int cache_time = 5; /* 5 ns */
 int memory_time = 60; /* 60 ns */

 printf("\nCache Time: %d ns, Memory Time: %d ns\n\n", cache_time, memory_time);

 double hit_rates[] = {99.0, 95.0, 90.0, 80.0, 50.0};

 printf("%-10s %-10s %-12s\n", "Hit Rate", "AMAT (ns)", "Speedup");
 printf("%-10s %-10s %-12s\n", "--------", "---------", "-------");

 for (int i = 0; i < 5; i++) {
 double amat = calculate_amat(cache_time, memory_time, hit_rates[i]);
 double speedup = (double)memory_time / amat;
 printf("%-10.1f %-10.2f %-12.2fx\n", hit_rates[i], amat, speedup);
 }

 printf("\nKey Insight: Even 95%% hit rate gives 7.75x speedup!\n");

 /* Cleanup */
 free(cache->cache_tags);
 free(cache);

 return 0;
}
